 1→import { useState } from 'react'
 2→import { setAuthToken } from '../store'
 3→import { api } from '../api'
 4→
 5→interface Props { onAuth: () => void }
 6→
 7→export default function Auth({ onAuth }: Props) {
 8→  const [token, setToken] = useState('')
 9→  const [error, setError] = useState('')
10→  const [loading, setLoading] = useState(false)
11→
12→  const handleSubmit = async () => {
13→    if (!token.trim()) { setError('Please enter your access token'); return }
14→    setLoading(true)
15→    setError('')
16→    setAuthToken(token.trim())
17→    try {
18→      const h = await api.health()
19→      if (h.status === 'ok') { onAuth() }
20→      else { setError('Unexpected response — check server'); setAuthToken('') }
21→    } catch (err) {
22→      const msg = err instanceof Error ? err.message : 'Unknown error'
23→      if (msg.includes('Unauthorized') || msg.includes('401')) {
24→        setError('Wrong token — check your APP_SECRET value')
25→      } else {
26→        setError('Cannot reach server — is it running?')
27→      }
28→      setAuthToken('')
29→    } finally { setLoading(false) }
30→  }
31→
32→  return (
33→    <div className="auth-gate">
34→      <div className="auth-card">
35→        <div className="auth-emoji">🎯</div>
36→        <h1 className="auth-title">DECODE</h1>
37→        <p className="auth-tagline">Your daily direction system</p>
38→        <div className="auth-divider" />
39→        <p className="auth-label">Enter your access token to continue</p>
40→        <input
41→          className={`auth-input ${error ? 'invalid' : ''}`}
42→          type="password"
43→          placeholder="Access token..."
44→          value={token}
45→          onChange={e => { setToken(e.target.value); setError('') }}
46→          onKeyDown={e => e.key === 'Enter' && handleSubmit()}
47→          autoFocus
48→        />
49→        {error && <div className="auth-error">{error}</div>}
50→        <button className="btn-primary btn-full mt-2" onClick={handleSubmit} disabled={loading}>
51→          {loading ? <span className="spinner show" /> : null}
52→          {loading ? 'Checking...' : 'Enter'}
53→        </button>
54→        <p className="auth-hint">Token is set via APP_SECRET in your .env file or Cloud Run environment variables.</p>
55→      </div>
56→    </div>
57→  )
58→}
